(11109, 'Arturo ballestero', '+34600 73 47 55', '38073775N', 'Reparación Móvil', NULL, NULL, 'ballesteroouroarturo@yahoo.es', NULL, NULL, 12.4, 0, 21, 15, 7.5, NULL, 'Nokia 520', 'Solicita tapa trasera de nokia 520', 'tapa', 'Barcelona', '2026-02-10 11:36:00', NULL, 0, 0, 'Otros', 'Hardware', 0, NULL, '', 'Solicita tapa trasera', 'Vince', NULL),
