(11112, 'margarita bignell', '+34692264235', '35046352x', 'Reparación Móvil', NULL, NULL, 'margabignell@gmail.com', NULL, NULL, 61.12, 0, 21, 73.95, 50, 'Tarjeta', 'iphone 11', 'Cliente solicita cambio de pin de carga y bateria.', NULL, 'Barcelona', '2026-02-11 10:46:00', '2026-02-11 18:14:00', 0, 4, 'Sin especificar', 'Hardware', 1, NULL, '308767', 'Cambio pin de carga y bateria', NULL, NULL),
