(11114, 'juan antonio cordobes aranda', '+34675638951', '43512268v', 'Mantenimiento Otros', NULL, NULL, 'juanantonio.cordobes@gmail.com', NULL, NULL, 37.19, 0, 21, 45, 0, NULL, 'smartwatch lotus 50050', 'Cliente dice que luego de que lo haya sumergido dejo de funcionar correctamente, la pantalla enciende pero el touch no respode. \r\nGARANTIA: Cliente declara que se levanto un día por la mañana intento cargarlo y no respondia. El dispositivo tiene un golpe en la parte superior de la pantalla.\r\n', NULL, 'Barcelona', '2026-02-13 12:13:00', NULL, 10977, 3, 'Sin especificar', 'Hardware', 1, NULL, '', 'No enciende', NULL, NULL),
